package com.hzltd.module.erplus.ai.mas.runtime.prompt.schema;

import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.List;

/**
 * Represents a high-level strategic plan for a large UserGoal.
 * Generated by the ProjectManagerAgent.
 */
@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class StrategicPlan {
    /**
     * Reasoning behind the decomposition.
     */
    private String reasoning;

    /**
     * Recommended execution type for the root container (SEQUENTIAL or PARALLEL).
     */
    private String parentTaskType;

    /**
     * List of high-level business tasks.
     */
    private List<StrategicTask> tasks;
}
